<template>
	<view class="help-pay-page">




		<!-- 订单信息卡片 -->
		<view class="order-card">
			<view class="order-header">
				<text class="order-title">帮我付订单信息</text>
				<text class="order-status">待支付</text>
			</view>
			<view class="order-amount">¥{{order.total_price}}</view>
			<view class="order-note">实际金额以付款人确认付款时为准</view>
			<view class="order-item">
				<view class="item-icon">🤝</view>
				<text class="item-desc">{{order.goods_name}}</text>
			</view>
		</view>

		<!-- 选择支付宝好友 -->
		<view class="friend-section">
			<view class="section-title">选择支付宝好友</view>
			<view class="search-bar">
				<text class="search-icon">🔍</text>
				<input class="search-input" placeholder="输入手机号、邮箱、好友姓名查找" />
			</view>
			<view class="suggested-friend">
				<text class="suggest-title">你可能想找</text>
				<view class="friend-item" @click="selectFriend" v-for="(friend, index) in randomFriends" :key="index">
					<image class="friend-avatar" :src="$util.img(friend.img)" />
					<view class="friend-info">
						<text class="friend-name">{{friend.name}}</text>
						<text class="friend-tag">好友</text>
					</view>
					<text class="friend-phone">{{friend.phone}}</text>
					<text class="arrow"></text>
				</view>
			</view>
		</view>

		<!-- 服务提供商信息 -->
		<view class="service-info">
			<text class="service-text">本服务由支付宝(中国)网络技术有限公司提供</text>
		</view>

		<!-- 选择其他好友 -->
		<view class="other-friends">
			<view class="section-title">选择其他好友</view>
			<view class="friend-options">
				<view class="option-item" @click="parse('分享到微信好友')">
					<!-- 	<view class="option-icon wechat">
						<text class="icon-text">💬</text>
					</view> -->
					<u-icon size="100" color="#46bb36" style="margin-bottom:10rpx;" name="weixin-circle-fill"></u-icon>
					<text class="option-text">微信好友</text>
				</view>
				<view class="option-item" @click="parse('生成二维码分享')">
					<view class="option-icon qrcode">
						<text class="icon-text">📱</text>
					</view>
					<text class="option-text">二维码分享</text>
				</view>
				<view class="option-item" @click="parse('分享给支付宝好友')">
					<!-- <view class="option-icon alipay">
						<text class="icon-text">支</text>
					</view> -->
					<u-icon size="100" color="#4abcff" style="margin-bottom:10rpx;"
						name="zhifubao-circle-fill"></u-icon>
					<text class="option-text">支付宝好友</text>
				</view>
				<view class="option-item" @click="parse('分享给通讯录好友')">
					<view class="option-icon contacts">
						<text class="icon-text">👥</text>
					</view>
					<text class="option-text">通讯录好友</text>
				</view>
				<view class="option-item" @click="parse('复制链接成功')">
					<view class="option-icon link">
						<text class="icon-text">🔗</text>
					</view>
					<text class="option-text">复制链接</text>
				</view>
			</view>
		</view>

	</view>
</template>

<script>
	import {
		mapGetters,
		mapActions
	} from 'vuex'
	export default {
		data() {
			return {
				pageShareUrl: '',
				randomFriends: [],
				// 模拟好友数据池
				friendPool: [{
						name: '**双',
						phone: '152******77',
						img: '/statics/images/avatar/0.jpg'
					},
					{
						name: '**明',
						phone: '138******66',
						img: '/statics/images/avatar/1.jpg'
					},
					{
						name: '**婷',
						phone: '139******88',
						img: '/statics/images/avatar/2.jpg'
					},
					{
						name: '**强',
						phone: '159******55',
						img: '/statics/images/avatar/3.jpg'
					},
					{
						name: '**芳',
						phone: '188******99',
						img: '/statics/images/avatar/4.jpg'
					}
				],
				order: {}
			}
		},
		onLoad() {
			if (!this.sysconfig.change_site_info) {
				this.$util.on('/pages/index/index')
				return 
			}
			this.shareConfig()
			this.generateRandomFriends()


			//从缓存中获取
			uni.getStorage({
				key: 'bangOrderInfo',
				success: (res) => {
					let data = JSON.parse(res.data)

					this.order = data
					// this.loadData()
				},
				fail: (e) => {
					this.$util.back()
				}
			});
		},

		methods: {
			async shareConfig() {
				const {
					page_share_url,
					sharewxgzhConfig
				} = await this.$u.api.shareConfig(this.queryForm)
				this.pageShareUrl = page_share_url

			},
			// 生成随机两个好友数据
			generateRandomFriends() {
				// 从好友池中随机选择两个不重复的好友
				const shuffled = [...this.friendPool].sort(() => 0.5 - Math.random());
				this.randomFriends = shuffled.slice(0, 2);
			},

			goBack() {
				uni.navigateBack()
			},
			selectFriend() {
				console.log('选择好友')
			},
			selectWeChat() {
				uni.showToast({
					title: '分享到微信好友',
					icon: 'none'
				})
			},
			selectQRCode() {
				uni.showToast({
					title: '生成二维码分享',
					icon: 'none'
				})
			},
			selectAlipay() {
				uni.showToast({
					title: '分享到支付宝好友',
					icon: 'none'
				})
			},
			selectContacts() {
				uni.showToast({
					title: '分享到通讯录好友',
					icon: 'none'
				})
			},
			parse(val) {

				setTimeout(() => {
					uni.setClipboardData({
						data: this.pageShareUrl,
						success: () => {
							uni.showToast({
								title: val,
								icon: 'none'
							})
						}
					})
				}, 80)
			}
		}
	}
</script>

